import java.util.*

fun solve(nums: Array<Long>): Long {
    val n = nums.size
    val queue = LinkedList<Int>()
    val visited = BooleanArray(n)
    queue.add(0)
    visited[0] = true
    var steps = 0

    while (queue.isNotEmpty()) {
        val size = queue.size
        for (i in 0 until size) {
            val current = queue.removeFirst()
            if (current == n - 1) return steps.toLong()
            // Move to adjacent cells
            if (current > 0 && !visited[current - 1]) {
                visited[current - 1] = true
                queue.add(current - 1)
            }
            if (current < n - 1 && !visited[current + 1]) {
                visited[current + 1] = true
                queue.add(current + 1)
            }
            // Prime teleport
            if (isPrime(nums[current])) {
                val p = nums[current]
                for (j in 1 until n) {
                    if (nums[j] % p == 0 && j != current && !visited[j]) {
                        visited[j] = true
                        queue.add(j)
                    }
                }
            }
        }
        steps++
    }
    return -1L
}

fun isPrime(num: Long): Boolean {
    if (num <= 1) return false
    if (num == 2) return true
    if (num % 2 == 0) return false
    val sqrtNum = Math.sqrt(num.toDouble()).toInt()
    for (i in 3..sqrtNum step 2) {
        if (num % i == 0) return false
    }
    return true
}
